const imageWidth = "100%"; // Define image width
const imageHeight = "auto"; // Define image height

export default function GioiThieu() {
  return (
    <>
      <HomeHeader />
      <HomeBoxChat />

      <div className="container mx-auto py-8">
        <motion.section
          variants={sectionVariants}
          initial="hidden"
          whileInView="visible"
          viewport={{ once: true }}
          className="mb-12"
        >
          <h2 className="text-3xl font-bold text-center mb-6">Về Chúng Tôi</h2>
          {aboutUsData.map((item) => (
            <div
              key={item.id}
              className="grid grid-cols-1 md:grid-cols-2 gap-8 mb-8"
            >
              <div className="flex items-center justify-center">
                <Image
                  src={item.image}
                  alt={item.title}
                  width={500} // Adjust as needed
                  height={300} // Adjust as needed
                  style={{
                    width: imageWidth,
                    height: imageHeight,
                    objectFit: "cover",
                  }}
                />
              </div>
              <div>
                <h3 className="text-2xl font-semibold mb-4">{item.title}</h3>
                <p className="text-gray-700">{item.description}</p>
              </div>
            </div>
          ))}
        </motion.section>

        <motion.section
          variants={sectionVariants}
          initial="hidden"
          whileInView="visible"
          viewport={{ once: true }}
        >
          <h2 className="text-3xl font-bold text-center mb-6">
            Chăm Sóc Khách Hàng
          </h2>
          {customerCareData.map((item) => (
            <div
              key={item.id}
              className="grid grid-cols-1 md:grid-cols-2 gap-8 mb-8"
            >
              <div className="flex items-center justify-center">
                <Image
                  src={item.image}
                  alt={item.title}
                  width={500} // Adjust as needed
                  height={300} // Adjust as needed
                  style={{
                    width: imageWidth,
                    height: imageHeight,
                    objectFit: "cover",
                  }}
                />
              </div>
              <div>
                <h3 className="text-2xl font-semibold mb-4">{item.title}</h3>
                <p className="text-gray-700">{item.description}</p>
              </div>
            </div>
          ))}
        </motion.section>
      </div>

      <HomeFooter />
    </>
  );
}
